const url = 'http://127.0.0.1:8000/api/recommendations';
const payload = {
  skill: 'react',
  difficulty: 'intermediate',
  max_results: 10,
  preferences: ['hooks', 'state management']
};

fetch(url, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(payload)
})
  .then(response => response.json())
  .then(data => {
    console.log(`Found ${data.total_results} recommendations`);
    data.recommendations.forEach(course => {
      console.log(`- ${course.title} (${course.provider})`);
    });
  })
  .catch(error => console.error('Error:', error));

const axios = require('axios');

const url = 'http://127.0.0.1:8000/api/recommendations';
const payload = {
  skill: 'nodejs',
  difficulty: 'beginner',
  max_results: 8,
  preferences: ['express', 'api development']
};

axios.post(url, payload)
  .then(response => {
    const data = response.data;
    console.log(`Found ${data.total_results} recommendations`);
    data.recommendations.forEach(course => {
      console.log(`${course.title} - Score: ${course.relevance_score}`);
    });
  })
  .catch(error => console.error('Error:', error));
